{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-eval-test-set-curation-output",
  "required": [
    "trajectory_count",
    "real_trace_fraction",
    "tag_schema",
    "partition",
    "version_control_path",
    "forbidden_seen"
  ],
  "properties": {
    "trajectory_count": {
      "description": "\u226530."
    },
    "real_trace_fraction": {
      "description": "\u22650.3."
    },
    "tag_schema": {
      "description": "{capability[], persona[], difficulty[1..5]}."
    },
    "partition": {
      "description": "{fast_subset_pct, full_suite_remainder}."
    },
    "version_control_path": {
      "description": "Git path."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
